def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        base_score = 0
        if ratio == 1:
            base_score = 0
        elif ratio > 0.75:
            base_score = (1 - ratio) * 2 + np.sqrt(capacity) / 10
        elif ratio > 0.5:
            base_score = (0.75 - ratio) ** 1.5 + 0.05 * np.log1p(capacity)
        else:
            base_score = (0.5 - ratio) ** 2 + 0.2
        neighbor_score = 0
        for offset in range(1, 6):
            left_idx = i - offset
            right_idx = i + offset
            weight = 1 / offset
            if left_idx >= 0 and bins[left_idx] > 0:
                diff_ratio = abs(capacity - bins[left_idx]) / bins[left_idx]
                neighbor_score += weight * diff_ratio
                if ratio > 0.5 and bins[left_idx] < item:
                    neighbor_score += 0.1 * weight
            if right_idx < n and bins[right_idx] > 0:
                diff_ratio = abs(capacity - bins[right_idx]) / bins[right_idx]
                neighbor_score += weight * diff_ratio
                if ratio > 0.5 and bins[right_idx] < item:
                    neighbor_score += 0.1 * weight
        penalty = 0
        if capacity < item * 1.2:
            penalty += 0.3
        if capacity > item * 3:
            penalty -= 0.1
        score = base_score + neighbor_score + penalty
        if score < 0:
            score = 0
        priorities[i] = score
    min_finite = np.min(priorities[np.isfinite(priorities)])
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_finite * 5 + i * 0.01
    return priorities
